SELECT a.id, a.attribute_name, a.attribute_en_name, a.attribute_type_id, a.attribute_type_name, a.id AS attribute_id, b.tag_id, b.tag_name FROM (SELECT attribute_id, tag_id, tag_name FROM kol_tag_attribute_relation WHERE platform_type = #{searchModel.platformType}
and product_id = #{searchModel.productId}
) b INNER JOIN ${searchModel.tempTableName} c ON b.tag_name = c.tag_name INNER JOIN kol_attribute a ON a.id = b.attribute_id

SELECT DISTINCT ka.id
FROM kol_attribute ka
WHERE ka.attribute_name IN (
SELECT SUBSTRING_INDEX(ka3.attribute_name_path, '|', 1)
FROM kol_attribute ka3
INNER JOIN kol_tag_attribute_relation ktar
ON ka3.id = ktar.attribute_id and ktar.product_id = #{productId}
INNER JOIN kol_tag_product ktp
ON ktar.tag_id = ktp.tag_id and ktp.product_id = #{productId}


		and ktp.platform_type = #{platformType}


)
